referenceSolutions:
@layer reset, base, components, utilities;

@layer reset {
  h2, p {
    margin: 0;
    padding: 0;
  }
}

@layer base {
  * {
    font-family: system-ui, sans-serif;
    color: rgb(51, 51, 51);
  }
}

@layer components {
  .card-component {
    border: 1px solid rgb(221, 221, 221);
    padding: 24px;
    border-radius: 8px;
    max-width: 400px;
  }
  .card-heading {
    font-size: 20px;
    margin-bottom: 8px;
    color: rgb(0, 123, 255);
  }
  .card-text {
    margin-bottom: 16px;
    line-height: 1.5;
  }
  .btn-primary {
    background-color: rgb(0, 123, 255);
    color: rgb(255, 255, 255);
    border: none;
    padding: 10px 20px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 14px;
  }
}

@layer utilities {
  .text-uppercase {
    text-transform: uppercase;
  }
}

